module.exports = function(RED) {
    function ActionNode(config) {
        RED.nodes.createNode(this, config);
        var node = this;

        node.name = config.name;
        node.actions = [];

        for (var i = 1; i <= 9; i++) {
            var actionValue = config["action" + i];
            if (actionValue && actionValue.trim() !== "") {
                node.actions.push(actionValue.trim());
            }
        }

        node.on('input', function(msg) {
            // Ajoute les actions au message si vous souhaitez tout de même manipuler l'objet msg en interne
            msg.actions = node.actions;
            
            // node.send(msg) a été supprimé car il n'y a plus de sortie physique.
        });
    }
    RED.nodes.registerType("action", ActionNode);
}